import { useEffect, useState, type FormEvent } from 'react'
import { useLocation } from 'react-router-dom'
import { MarketQuoteSection } from './components/MarketQuote'
import { SectionTabs } from './SectionTabs'
import { farmerError } from './lib/farmerErrors'
import type { GrainAlertSettings, GrainContract, GrainContractType, GrainServices, GrainWorkspace, MarketingAlertRule, MarketingAlertRuleType, MarketingPlanTarget, PositionScope, ProductionEstimate } from './data/grain'
import { marketedPercent, sameScope, scopeOf } from './data/grain'
import { evaluateGrainAlerts, requestOwnerAlertDelivery, type GrainAlert } from './data/grainAlerts'
import { evaluateMarketingAlertRules, ruleSentence } from './data/marketingAlerts'
import { isMarsBid, latestBasis } from './data/basisMath'
import { GrainCostOfCarry } from './GrainCostOfCarry'

const money = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: 2 })
const bushels = new Intl.NumberFormat('en-US', { maximumFractionDigits: 0 })
const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec']
const contractLabels: Record<GrainContractType, string> = { cash_spot: 'Cash / spot', forward_cash: 'Forward cash', basis: 'Basis', hta: 'HTA' }
const GRAIN_TABS = [{ slug: '', label: 'Overview' }, { slug: 'plan', label: 'Marketing plan' }, { slug: 'alerts', label: 'Alerts' }, { slug: 'carry', label: 'Cost of carry' }, { slug: 'contracts', label: 'Contracts' }, { slug: 'storage', label: 'Bins & basis' }]
type Template = 'balanced' | 'harvest' | 'storage' | 'conservative' | 'seasonal'
const templates: Record<Template, { name: string; description: string; total: number; schedule: Array<[number, number]> }> = {
  balanced: { name: 'Balanced Seller', description: '60% planned; 40% deliberately unplanned.', total: 60, schedule: [[3, 10], [5, 10], [7, 10], [9, 15], [11, 15]] },
  harvest: { name: 'Harvest Heavy', description: '65% planned; 35% deliberately unplanned.', total: 65, schedule: [[6, 8], [8, 12], [9, 25], [10, 20]] },
  storage: { name: 'Storage Heavy', description: '70% planned; 30% deliberately unplanned.', total: 70, schedule: [[5, 10], [8, 10], [11, 10], [1, 20], [3, 20]] },
  conservative: { name: 'Conservative Pre-Harvest', description: '55% planned; 45% deliberately unplanned.', total: 55, schedule: [[2, 10], [4, 15], [6, 15], [8, 15]] },
  seasonal: { name: 'Seasonal Seller', description: '60% planned; 40% deliberately unplanned.', total: 60, schedule: [[2, 10], [4, 15], [6, 15], [7, 10], [10, 10]] },
}

function finalCashPrice(contract: GrainContract): number | null {
  const premium = contract.premium_cents_per_bu / 100
  if (contract.cash_price !== null) return contract.cash_price + premium
  if (contract.futures_price !== null && contract.basis !== null) return contract.futures_price + contract.basis + premium
  return null
}
function manualPlannedPrice(workspace: GrainWorkspace, scope: PositionScope) { const targets = scopeRows(workspace.marketing_plan_targets, scope).filter((target): target is MarketingPlanTarget & { target_price: number } => target.target_price !== null); const weightedBushels = targets.reduce((sum, target) => sum + target.target_pct_of_production, 0); return weightedBushels ? targets.reduce((sum, target) => sum + target.target_price * target.target_pct_of_production, 0) / weightedBushels : null }
function expectedIpPremium(workspace: GrainWorkspace, scope: PositionScope) { const commodity = workspace.fields.commodities.find((item) => item.id === scope.commodity_id); if (!commodity?.traits.premium_eligible) return 0; const premiums = workspace.grain_contracts.filter((contract) => sameScope(contract, scope) && contract.premium_cents_per_bu > 0); return (premiums.length ? premiums.reduce((sum, contract) => sum + contract.premium_cents_per_bu, 0) / premiums.length : 25) / 100 }
function activeProduction(estimate: ProductionEstimate) { return estimate.drives_math === 'actual' && estimate.actual_bushels !== null ? estimate.actual_bushels : estimate.expected_bushels }
function scopeRows<T extends PositionScope>(rows: T[], scope: PositionScope) { return rows.filter((row) => sameScope(row, scope)) }
function scopeLabel(workspace: GrainWorkspace, scope: PositionScope) { const commodity = workspace.fields.commodities.find((item) => item.id === scope.commodity_id)?.name ?? scope.commodity_id; const entity = scope.enterprise_label ?? workspace.fields.entities.find((item) => item.id === scope.operating_entity_id)?.name ?? 'whole farm'; return `${scope.crop_year} ${commodity} — ${entity}` }

export function GrainPage({ services }: { services: GrainServices }) {
  const [workspace, setWorkspace] = useState<GrainWorkspace | null>(null)
  const [selectedEstimateId, setSelectedEstimateId] = useState('')
  const [editingTarget, setEditingTarget] = useState<{ month: number; target?: MarketingPlanTarget } | null>(null)
  const [savedAt, setSavedAt] = useState('')
  const [planError, setPlanError] = useState('')
  const [loadError, setLoadError] = useState('')
  const [alerts, setAlerts] = useState<GrainAlert[]>([])
  const [deliveryNotice, setDeliveryNotice] = useState('')
  const rawTab = useLocation().pathname.split('/')[2] ?? ''
  const tabPath = ['plan', 'alerts', 'carry', 'contracts', 'storage'].includes(rawTab) ? rawTab : ''
  const refresh = async () => { try { const data = await services.grainRepository.getData(); const ruleEvaluation = evaluateMarketingAlertRules(data); const nextAlerts = evaluateGrainAlerts(data); setWorkspace(data); setAlerts(nextAlerts); if (ruleEvaluation.firedRuleIds.length) { const stamp = new Date().toISOString(); void Promise.all(ruleEvaluation.firedRuleIds.map((id) => { const rule = data.marketing_alert_rules.find((item) => item.id === id); return rule ? services.grainRepository.saveMarketingAlertRule({ ...rule, last_triggered_at: stamp, updated_at: stamp }) : Promise.resolve() })) } void requestOwnerAlertDelivery(nextAlerts, data.fields.farm.id).then((failed) => setDeliveryNotice(failed.length ? 'An email notice could not be sent. Your in-app alert is still here.' : '')); setLoadError(''); setSelectedEstimateId((current) => data.production_estimates.some((estimate) => estimate.id === current) ? current : data.production_estimates[0]?.id ?? '') } catch (caught) { const message = caught instanceof Error && caught.message === 'GRAIN_PRIVATE_ACCESS_DENIED' ? 'Grain records are private on this farm. Ask the farm owner or manager if you need access.' : farmerError(caught, 'load your grain records'); setLoadError(message) } }
  useEffect(() => { void refresh() }, [])
  const whisper = () => setSavedAt(`Saved ${new Intl.DateTimeFormat('en-US', { hour: 'numeric', minute: '2-digit' }).format(new Date())}`)
  if (!workspace) return <section className="page"><div className="loading-state" role={loadError ? 'alert' : undefined}>{loadError || 'Loading grain position…'}</div></section>
  const selectedEstimate = workspace.production_estimates.find((estimate) => estimate.id === selectedEstimateId) ?? workspace.production_estimates[0]
  if (!selectedEstimate) return <FirstEstimate workspace={workspace} services={services} onSaved={refresh} />
  const selectedScope = scopeOf(selectedEstimate)
  const selectedCommodityName = workspace.fields.commodities.find((commodity) => commodity.id === selectedScope.commodity_id)?.name ?? selectedScope.commodity_id
  const saveTarget = async (values: { pct: number; price: number | null; relativePct: number | null; deadline: string | null }) => {
    if (!editingTarget) return
    const timestamp = new Date().toISOString()
    const target: MarketingPlanTarget = editingTarget.target ? { ...editingTarget.target, target_pct_of_production: values.pct, target_price: values.price, breakeven_relative_pct: values.relativePct, deadline: values.deadline, updated_at: timestamp } : { id: services.createGrainId(), ...selectedScope, target_month: `${selectedScope.crop_year}-${String(editingTarget.month).padStart(2, '0')}-01`, target_pct_of_production: values.pct, target_price: values.price, breakeven_relative_pct: values.relativePct, deadline: values.deadline, notes: null, created_at: timestamp, updated_at: timestamp }
    try { await services.grainRepository.saveMarketingPlanTarget(target); setEditingTarget(null); setPlanError(''); whisper(); await refresh() } catch (error) { setPlanError(error instanceof Error ? error.message : 'Unable to save this target.') }
  }
  const applyTemplate = async (template: Template) => {
    const timestamp = new Date().toISOString()
    const targets = templates[template].schedule.map(([month, pct]) => ({ id: services.createGrainId(), ...selectedScope, target_month: `${selectedScope.crop_year}-${String(month).padStart(2, '0')}-01`, target_pct_of_production: pct, target_price: null, breakeven_relative_pct: null, deadline: `${selectedScope.crop_year}-${String(month).padStart(2, '0')}-28`, notes: null, created_at: timestamp, updated_at: timestamp }))
    try { await services.grainRepository.replaceMarketingPlanTargets(selectedScope, targets); setPlanError(''); whisper(); await refresh() } catch (error) { setPlanError(error instanceof Error ? error.message : 'Unable to apply this plan.') }
  }
  return <section className="page grain-page">
    <div className="page-heading grain-heading"><div><h1>Grain</h1><p>Your position, your targets, and nothing more. <span className="delayed-label">Market quotes are delayed.</span></p></div></div>
    <SectionTabs base="/grain" tabs={GRAIN_TABS} />
    {tabPath === '' && <>
    {alerts.length > 0 && <section className="grain-section" aria-label="Grain alerts"><div className="section-heading"><div><span className="eyebrow">Check-on-open alerts</span><h2>Items to review</h2><p>These are checked only when the farm owner opens Grain; they are not 24/7 monitoring.</p></div></div>{alerts.map((alert) => <p key={alert.key} role="status">{alert.message}</p>)}</section>}
    {deliveryNotice && <p className="form-error grain-inline-error" role="status">{deliveryNotice}</p>}
    <MarketQuoteSection />
    <section aria-label="Commodity positions" className="position-grid">{workspace.production_estimates.map((estimate) => <PositionCard key={estimate.id} estimate={estimate} workspace={workspace} services={services} onSaved={async () => { whisper(); await refresh() }} />)}</section>
    </>}
    {tabPath === 'plan' && <>
    <section className="grain-section plan-card"><div className="section-heading"><div><span className="eyebrow">Primary plan</span><h2>Monthly marketing plan</h2><p>Set coverage by month. A plan can intentionally leave bushels unplanned.</p></div><label className="commodity-picker"><span>Commodity</span><select value={selectedEstimate.id} onChange={(event) => setSelectedEstimateId(event.target.value)}>{workspace.production_estimates.map((estimate) => <option key={estimate.id} value={estimate.id}>{workspace.fields.commodities.find((commodity) => commodity.id === estimate.commodity_id)?.name}</option>)}</select></label></div>
      <div className="template-bar" aria-label="Marketing plan templates">{(Object.keys(templates) as Template[]).map((key) => <button key={key} type="button" className="template-button" onClick={() => void applyTemplate(key)}><strong>{templates[key].name}</strong><span>{templates[key].description}</span></button>)}</div>
      <div className="month-grid">{months.map((month, index) => { const number = index + 1; const target = scopeRows(workspace.marketing_plan_targets, selectedScope).find((item) => Number(item.target_month.slice(5, 7)) === number); return <button className={`month-cell${target ? ' planned' : ''}`} type="button" key={month} onClick={() => setEditingTarget({ month: number, target })}><span>{month}</span><strong>{target ? `${target.target_pct_of_production}%` : '—'}</strong><small>{target?.target_price === null || target?.target_price === undefined ? (target ? 'Add manual price' : 'No target set') : `Manual target ${money.format(target.target_price)}`}</small></button> })}</div>
      {planError && <p className="form-error grain-inline-error" role="alert">{planError}</p>}<PlanStatus estimate={selectedEstimate} workspace={workspace} /></section>
    <ActualVsPlan estimate={selectedEstimate} workspace={workspace} />
    </>}
    {tabPath === 'carry' && <GrainCostOfCarry workspace={workspace} selectedEstimate={selectedEstimate} selectedEstimateId={selectedEstimateId} onSelectEstimate={setSelectedEstimateId} />}
    {tabPath === 'alerts' && <MarketingAlerts workspace={workspace} services={services} selectedEstimateId={selectedEstimateId} onSelectEstimate={setSelectedEstimateId} onSaved={async () => { whisper(); await refresh() }} />}
    {tabPath === 'contracts' && <section className="grain-section contracts-card"><div className="section-heading"><div><span className="eyebrow">15-second entry</span><h2>Contracts</h2><p>Record a sale; the position updates from it.</p></div>{savedAt && <span className="saved-whisper" role="status">{savedAt}</span>}</div><ContractEntry workspace={workspace} scope={selectedScope} services={services} onSaved={async () => { whisper(); await refresh() }} /><div className="table-scroll"><table><thead><tr><th>Buyer</th><th>Commodity</th><th>Type</th><th className="align-right">Bushels</th><th className="align-right">Price</th><th>Delivery</th></tr></thead><tbody>{scopeRows(workspace.grain_contracts, selectedScope).map((contract) => <tr key={contract.id}><td><strong>{contract.buyer}</strong><small>{contract.contract_number ?? 'No contract #'}</small></td><td>{workspace.fields.commodities.find((commodity) => commodity.id === contract.commodity_id)?.name}</td><td>{contractLabels[contract.contract_type]}</td><td className="align-right numeric">{bushels.format(contract.bushels)}</td><td className="align-right numeric">{finalCashPrice(contract) === null ? (contract.contract_type === 'hta' ? 'Basis open' : 'Futures open') : money.format(finalCashPrice(contract)!)}</td><td>{contract.delivery_start?.slice(5).replace('-', '/') ?? '—'}</td></tr>)}</tbody></table></div></section>}
    {tabPath === 'storage' && <section className="grain-section storage-layout"><Bins workspace={workspace} /><Basis workspace={workspace} services={services} onSaved={async () => { whisper(); await refresh() }} /></section>}
    {tabPath === '' && <UsdaCalendar reports={workspace.usda_report_dates} />}
    <aside className="compliance-note"><strong>For your records.</strong> Farm Rx shows your numbers and your targets. It does not give marketing advice. <span>Owner-only alerts are best-effort check-on-open notices, not 24/7 monitoring.</span></aside>
    {editingTarget && <TargetEditor month={editingTarget.month} commodity={selectedCommodityName} target={editingTarget.target} scope={selectedScope} services={services} workspace={workspace} onClose={() => { setEditingTarget(null); setPlanError('') }} onSave={saveTarget} />}
  </section>
}

function MarketingAlerts({ workspace, services, selectedEstimateId, onSelectEstimate, onSaved }: { workspace: GrainWorkspace; services: GrainServices; selectedEstimateId: string; onSelectEstimate: (id: string) => void; onSaved: () => Promise<void> }) {
  const [draftType, setDraftType] = useState<MarketingAlertRuleType | null>(null); const [editing, setEditing] = useState<MarketingAlertRule | null>(null); const [error, setError] = useState('')
  const selected = workspace.production_estimates.find((estimate) => estimate.id === selectedEstimateId) ?? workspace.production_estimates[0]
  if (!selected) return null
  const scope = scopeOf(selected); const commodity = workspace.fields.commodities.find((item) => item.id === scope.commodity_id)?.name ?? scope.commodity_id
  const currentPct = marketedPercent(workspace, scope); const rules = workspace.marketing_alert_rules.filter((rule) => sameScope(rule, scope)); const otherRules = workspace.marketing_alert_rules.filter((rule) => !workspace.production_estimates.some((estimate) => sameScope(estimate, rule)))
  const start = (type: MarketingAlertRuleType) => { setError(''); setEditing(null); setDraftType(type) }
  const save = async (rule: MarketingAlertRule) => { try { await services.grainRepository.saveMarketingAlertRule(rule); setError(''); setDraftType(null); setEditing(null); await onSaved() } catch (caught) { const message = farmerError(caught, 'save this alert'); setError(message); throw new Error(message) } }
  const remove = async (id: string) => { if (!window.confirm('Delete this alert rule?')) return; try { await services.grainRepository.deleteMarketingAlertRule(id); setError(''); await onSaved() } catch (caught) { setError(farmerError(caught, 'delete this alert')) } }
  const toggle = async (rule: MarketingAlertRule) => { try { await services.grainRepository.saveMarketingAlertRule({ ...rule, active: !rule.active, updated_at: new Date().toISOString() }); setError(''); await onSaved() } catch (caught) { setError(farmerError(caught, 'update this alert')) } }
  return <>
    <section className="grain-section alerts-card"><div className="section-heading"><div><span className="eyebrow">Check-on-open alerts</span><h2>Marketing alerts</h2><p>Farm Rx checks these when you open Grain. They are not 24/7 monitoring.</p></div><label className="commodity-picker"><span>Commodity</span><select value={selected.id} onChange={(event) => { setError(''); onSelectEstimate(event.target.value) }}>{workspace.production_estimates.map((estimate) => <option key={estimate.id} value={estimate.id}>{scopeLabel(workspace, estimate)}</option>)}</select></label></div>
       <div className="alert-template-row" aria-label="Alert templates"><button className="alert-template" type="button" onClick={() => start('price_target')}><strong>Price target</strong><span>Tell me when {commodity.toLowerCase()} hits my number</span></button><button className="alert-template" type="button" onClick={() => start('pct_marketed_goal')}><strong>% marketed goal</strong><span>Remind me if I fall behind my marketing plan</span></button><button className="alert-template" type="button" onClick={() => start('deadline')}><strong>Deadline</strong><span>Remind me before a date</span></button></div>
       {(draftType || editing) && <AlertRuleForm key={`${editing?.id ?? 'new'}:${editing?.rule_type ?? draftType}`} workspace={workspace} services={services} scope={scope} commodity={commodity} currentPct={currentPct} rule={editing} type={editing?.rule_type ?? draftType!} onCancel={() => { setEditing(null); setDraftType(null) }} onSave={save} />}
       <div className="alert-rule-list">{rules.length ? rules.map((rule) => <article key={rule.id} className={`alert-rule${rule.active ? '' : ' paused'}`}><div><strong>{ruleSentence(rule, commodity)}</strong>{rule.message && <span>{rule.message}</span>}{rule.last_triggered_at && <small>Last fired {new Date(rule.last_triggered_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</small>}</div><div className="alert-rule-actions"><button className="secondary-action" type="button" onClick={() => void toggle(rule)}>{rule.active ? 'Pause' : 'Resume'}</button><button className="text-action" type="button" onClick={() => { setError(''); setEditing(rule); setDraftType(null) }}>Edit</button><button className="text-action danger-action" type="button" onClick={() => void remove(rule.id)}>Delete</button></div></article>) : <p className="alert-empty">No alerts for this commodity and crop year yet. Choose a template above.</p>}</div>
       {error && <p className="form-error grain-inline-error" role="alert">{error}</p>}
       {otherRules.length > 0 && <div className="alert-rule-list"><h3>Other alerts</h3><p>These alerts do not have a production estimate in the picker, but you can still pause or delete them.</p>{otherRules.map((rule) => <article key={rule.id} className={`alert-rule${rule.active ? '' : ' paused'}`}><div><strong>{scopeLabel(workspace, rule)}</strong><span>{ruleSentence(rule, workspace.fields.commodities.find((item) => item.id === rule.commodity_id)?.name ?? rule.commodity_id)}</span></div><div className="alert-rule-actions"><button className="secondary-action" type="button" onClick={() => void toggle(rule)}>{rule.active ? 'Pause' : 'Resume'}</button><button className="text-action danger-action" type="button" onClick={() => void remove(rule.id)}>Delete</button></div></article>)}</div>}
    </section>
    <AlertEmailSettings workspace={workspace} services={services} onSaved={onSaved} />
  </>
}

function AlertRuleForm({ workspace, services, scope, commodity, currentPct, rule, type, onCancel, onSave }: { workspace: GrainWorkspace; services: GrainServices; scope: PositionScope; commodity: string; currentPct: number; rule: MarketingAlertRule | null; type: MarketingAlertRuleType; onCancel: () => void; onSave: (rule: MarketingAlertRule) => Promise<void> }) {
  const [direction, setDirection] = useState<MarketingAlertRule['direction']>(rule?.direction ?? 'at_or_above'); const [threshold, setThreshold] = useState(rule?.threshold?.toString() ?? ''); const [remindOn, setRemindOn] = useState(rule?.remind_on ?? ''); const [message, setMessage] = useState(rule?.message ?? ''); const [breakeven, setBreakeven] = useState<number | null>(null); const [error, setError] = useState('')
  useEffect(() => { if (type === 'price_target') void services.profitabilityRepository.getBreakeven(scope, workspace.fields).then(setBreakeven) }, [type, services, scope.farm_id, scope.crop_year, scope.commodity_id, scope.operating_entity_id, scope.enterprise_label, workspace.fields])
  const submit = async (event: FormEvent) => { event.preventDefault(); const timestamp = new Date().toISOString(); const next: MarketingAlertRule = { id: rule?.id ?? services.createGrainId(), ...scope, rule_type: type, direction: type === 'price_target' ? direction : null, threshold: type === 'deadline' ? null : Number(threshold), remind_on: type === 'deadline' ? (remindOn || null) : null, message: message.trim() || null, active: rule?.active ?? true, last_triggered_at: rule?.last_triggered_at ?? null, created_at: rule?.created_at ?? timestamp, updated_at: timestamp }; try { await onSave(next) } catch (caught) { setError(caught instanceof Error ? caught.message : 'Unable to save this alert.') } }
  return <form className="alert-rule-form" onSubmit={(event) => void submit(event)}><div><h3>{rule ? 'Edit alert' : `New ${type === 'price_target' ? 'price target' : type === 'pct_marketed_goal' ? '% marketed goal' : 'deadline'}`}</h3><p>{scope.crop_year} {commodity}</p></div>{type === 'price_target' && <><label>When cash price is<select value={direction ?? 'at_or_above'} onChange={(event) => setDirection(event.target.value as MarketingAlertRule['direction'])}><option value="at_or_above">At or above</option><option value="at_or_below">At or below</option></select></label><label>Price target $/bu<input required type="number" min="0.01" max="1000" step="0.01" inputMode="decimal" value={threshold} onChange={(event) => setThreshold(event.target.value)} /></label><p className="alert-fact">Price alerts use the newest cash price entered for this commodity.</p>{breakeven !== null && <p className="alert-fact">Your break-even: {money.format(breakeven)}/bu</p>}</>}{type === 'pct_marketed_goal' && <><label>Marketed goal %<input required type="number" min="0.01" max="100" step="0.01" inputMode="decimal" value={threshold} onChange={(event) => setThreshold(event.target.value)} /></label><p className="alert-fact">Currently {currentPct.toFixed(0)}% marketed</p></>}{type === 'deadline' && <label>Reminder date<input required type="date" value={remindOn} onChange={(event) => setRemindOn(event.target.value)} /></label>}<label className="alert-note">Note <small>optional</small><input maxLength={1000} value={message} placeholder={type === 'deadline' ? 'Crop insurance sales close' : 'Add a note'} onChange={(event) => setMessage(event.target.value)} /></label>{error && <p className="form-error" role="alert">{error}</p>}<div className="alert-form-actions"><button className="primary-action" type="submit">Save alert</button><button className="text-action" type="button" onClick={onCancel}>Cancel</button></div></form>
}

function AlertEmailSettings({ workspace, services, onSaved }: { workspace: GrainWorkspace; services: GrainServices; onSaved: () => Promise<void> }) {
  const [emails, setEmails] = useState((workspace.grain_alert_settings?.alert_emails ?? []).join(', ')); const [error, setError] = useState(''); const [saved, setSaved] = useState('')
  useEffect(() => setEmails((workspace.grain_alert_settings?.alert_emails ?? []).join(', ')), [workspace.grain_alert_settings?.updated_at])
  const submit = async (event: FormEvent) => { event.preventDefault(); const addresses = emails.split(',').map((item) => item.trim()).filter(Boolean); const settings: GrainAlertSettings = { farm_id: workspace.fields.farm.id, alert_emails: addresses, updated_at: new Date().toISOString() }; try { await services.grainRepository.saveGrainAlertSettings(settings); setError(''); setSaved('Saved'); await onSaved() } catch (caught) { setError(farmerError(caught, 'save these alert email addresses')) } }
  return <section className="grain-section alert-email-card"><div className="section-heading"><div><span className="eyebrow">Delivery</span><h2>Email these alerts</h2><p>Add up to three addresses. If email is unavailable, your in-app alert stays here.</p></div></div><form onSubmit={(event) => void submit(event)}><label>Email addresses <small>Separate addresses with commas.</small><input value={emails} inputMode="email" placeholder="farmer@example.com, advisor@example.com" onChange={(event) => { setEmails(event.target.value); setSaved('') }} /></label>{error && <p className="form-error" role="alert">{error}</p>}<div><button className="primary-action" type="submit">Save emails</button>{saved && <span className="saved-whisper" role="status">{saved}</span>}</div></form></section>
}

function FirstEstimate({ workspace, services, onSaved }: { workspace: GrainWorkspace; services: GrainServices; onSaved: () => Promise<void> }) {
  const assignments = workspace.fields.crop_assignments
  const [aph, setAph] = useState(''); const [error, setError] = useState('')
  if (!assignments.length) return <section className="page"><div className="loading-state">Add a crop assignment in Fields to begin your grain position.</div></section>
  const grouped = new Map<string, typeof assignments[number]>(); for (const assignment of assignments) if (!grouped.has(`${assignment.crop_year}|${assignment.commodity_id}`)) grouped.set(`${assignment.crop_year}|${assignment.commodity_id}`, assignment)
  const create = async (assignment: typeof assignments[number]) => { const now = new Date().toISOString(); try { await services.grainRepository.saveProductionEstimate({ id: services.createGrainId(), farm_id: workspace.fields.farm.id, crop_year: assignment.crop_year, commodity_id: assignment.commodity_id, operating_entity_id: null, enterprise_label: null, planted_acres: null, aph_yield: Number(aph), expected_bushels: 0, actual_bushels: null, drives_math: 'projected', notes: null, created_at: now, updated_at: now }); setError(''); await onSaved() } catch (caught) { setError(caught instanceof Error ? caught.message : 'Unable to start this production estimate.') } }
  return <section className="page grain-page"><div className="page-heading grain-heading"><div><h1>Start your grain estimate</h1><p>Your live crop assignments are ready. Add an expected yield to create the first estimate.</p></div></div><label>APH / expected yield<input required type="number" min="0.01" step="any" value={aph} onChange={(event) => setAph(event.target.value)} /></label><div className="position-grid">{[...grouped.values()].map((assignment) => <article className="position-card" key={`${assignment.crop_year}|${assignment.commodity_id}`}><h2>{workspace.fields.commodities.find((item) => item.id === assignment.commodity_id)?.name ?? assignment.commodity_id}</h2><p>{assignment.crop_year} crop assignment</p><button className="primary-action" type="button" disabled={!Number.isFinite(Number(aph)) || Number(aph) <= 0} onClick={() => void create(assignment)}>Create estimate</button></article>)}</div>{error && <p className="form-error grain-inline-error" role="alert">{error}</p>}</section>
}

function PositionCard({ estimate, workspace, services, onSaved }: { estimate: ProductionEstimate; workspace: GrainWorkspace; services: GrainServices; onSaved: () => Promise<void> }) {
  const [aph, setAph] = useState(String(estimate.aph_yield)); const [actual, setActual] = useState(estimate.actual_bushels?.toString() ?? ''); const [error, setError] = useState(''); const [breakeven, setBreakeven] = useState<number | null>(null); const scope = scopeOf(estimate); useEffect(() => { void services.profitabilityRepository.getBreakeven(scope, workspace.fields).then(setBreakeven) }, [services, scope.farm_id, scope.crop_year, scope.commodity_id, scope.operating_entity_id, scope.enterprise_label, workspace.fields]); const commodity = workspace.fields.commodities.find((item) => item.id === scope.commodity_id)!; const production = activeProduction(estimate); const contracts = scopeRows(workspace.grain_contracts, scope); const finalContracts = contracts.filter((contract) => finalCashPrice(contract) !== null); const basisOpen = contracts.filter((contract) => contract.contract_type === 'hta' && finalCashPrice(contract) === null); const futuresOpen = contracts.filter((contract) => contract.contract_type === 'basis' && finalCashPrice(contract) === null); const basis = latestBasis(workspace, scope); const premium = expectedIpPremium(workspace, scope); const plannedPrice = manualPlannedPrice(workspace, scope); const plannedCash = plannedPrice === null ? null : plannedPrice + basis + premium; const finalBushels = finalContracts.reduce((sum, contract) => sum + contract.bushels, 0); const partiallyPricedBushels = [...basisOpen, ...futuresOpen].reduce((sum, contract) => sum + contract.bushels, 0); const outrightOpen = Math.max(0, production - finalBushels - partiallyPricedBushels); const finalRevenue = finalContracts.reduce((sum, contract) => sum + contract.bushels * (finalCashPrice(contract) ?? 0), 0); const partialRevenue = basisOpen.reduce((sum, contract) => sum + contract.bushels * ((contract.futures_price ?? 0) + basis + contract.premium_cents_per_bu / 100), 0) + (plannedPrice === null ? 0 : futuresOpen.reduce((sum, contract) => sum + contract.bushels * (plannedPrice + (contract.basis ?? 0) + contract.premium_cents_per_bu / 100), 0)); const plannedRevenue = plannedCash === null ? null : finalRevenue + partialRevenue + outrightOpen * plannedCash; const average = finalBushels ? finalRevenue / finalBushels : null; const pricedPct = production ? finalBushels / production * 100 : 0; const insurance = scopeRows(workspace.insurance_units, scope); const safeToForward = insurance.reduce((sum, unit) => sum + unit.insured_acres * unit.aph * unit.coverage_level_pct / 100, 0); const insuredAcres = insurance.reduce((sum, unit) => sum + unit.insured_acres, 0); const minRevenue = insuredAcres ? insurance.reduce((sum, unit) => sum + unit.revenue_guarantee_per_acre * unit.insured_acres, 0) / insuredAcres : null; const insuranceFloor = insurance.length ? insurance.reduce((sum, unit) => sum + unit.guarantee_per_bu * unit.insured_acres, 0) / insuredAcres : null
  const saveProduction = async (drives_math = estimate.drives_math) => { const parsedAph = Number(aph); const parsedActual = actual.trim() === '' ? null : Number(actual); try { await services.grainRepository.saveProductionEstimate({ ...estimate, aph_yield: parsedAph, actual_bushels: parsedActual, drives_math }); setError(''); await onSaved() } catch (exception) { setError(exception instanceof Error ? exception.message : 'Unable to save production.') } }
  return <article className="position-card"><div className="position-top"><div><span className="eyebrow">{commodity.crop_family === 'corn' ? 'Corn' : commodity.crop_family}</span><h2>{commodity.name}</h2></div><div className="math-toggle" role="group" aria-label={`${commodity.name} production basis`}><button type="button" className={estimate.drives_math === 'projected' ? 'active' : ''} onClick={() => void saveProduction('projected')}>Projected</button><button type="button" className={estimate.drives_math === 'actual' ? 'active' : ''} disabled={estimate.actual_bushels === null} onClick={() => void saveProduction('actual')}>Actual</button></div></div><p className="position-sentence">{Math.round(pricedPct)}% fully priced at {average === null ? '—' : money.format(average)} avg. Breakeven {breakeven === null ? '—' : money.format(breakeven)}. {bushels.format(basisOpen.reduce((sum, contract) => sum + contract.bushels, 0))} bu basis open and {bushels.format(futuresOpen.reduce((sum, contract) => sum + contract.bushels, 0))} bu futures open. {bushels.format(outrightOpen)} bu unpriced{plannedPrice === null ? '. Add a manual target price to estimate it.' : ` using your manual plan price of ${money.format(plannedPrice)}.`}</p><div className="position-stats"><Metric label="Fully priced" value={`${bushels.format(finalBushels)} bu`} note={`${Math.round(pricedPct)}%`} /><Metric label="Open legs" value={`${bushels.format(partiallyPricedBushels)} bu`} note="manual valuation" /><Metric label="Planned revenue" value={plannedRevenue === null ? '—' : money.format(plannedRevenue)} note={plannedRevenue === null ? 'add a manual price' : 'manual plan estimate'} /><Metric label="Safe to forward" value={`${bushels.format(safeToForward)} bu`} note={minRevenue === null ? 'no insurance unit' : `${money.format(minRevenue)}/ac min. rev.`} /></div><div className="production-editor"><label>Planted acres<strong>{estimate.planted_acres === null ? '—' : `${estimate.planted_acres.toLocaleString()} ac`}</strong></label><label>APH / expected yield<input type="number" min="0.01" step="any" value={aph} onChange={(event) => setAph(event.target.value)} /></label><label>Actual bushels<input type="number" min="0" step="1" value={actual} placeholder="Enter at harvest" onChange={(event) => setActual(event.target.value)} /></label><button type="button" className="secondary-action" onClick={() => void saveProduction()}>Save production</button></div>{error && <p className="form-error grain-inline-error" role="alert">{error}</p>}<div className="position-foot"><span>{estimate.drives_math === 'actual' ? 'Actual' : 'Projected'} production: <strong>{bushels.format(production)} bu</strong></span><span>{plannedPrice === null ? 'No manual plan price yet' : <>Manual plan price <strong>{money.format(plannedPrice)}</strong></>}{insuranceFloor !== null && <> · insurance floor {money.format(insuranceFloor)}</>}</span></div></article>
}
function Metric({ label, value, note }: { label: string; value: string; note: string }) { return <div><span>{label}</span><strong className="numeric">{value}</strong><small>{note}</small></div> }

function PlanStatus({ estimate, workspace }: { estimate: ProductionEstimate; workspace: GrainWorkspace }) { const scope = scopeOf(estimate); const production = activeProduction(estimate); const month = new Date().getMonth() + 1; const targets = scopeRows(workspace.marketing_plan_targets, scope); const targetPct = targets.filter((target) => Number(target.target_month.slice(5, 7)) <= month).reduce((total, target) => total + target.target_pct_of_production, 0); const contracted = scopeRows(workspace.grain_contracts, scope).reduce((total, contract) => total + contract.bushels, 0); const actualPct = production ? contracted / production * 100 : 0; const status = targets.length === 0 ? 'Not started' : actualPct >= targetPct ? 'On Track' : 'Behind'; const totalPlanned = targets.reduce((total, target) => total + target.target_pct_of_production, 0); return <div className="plan-status"><div><span>Plan progress through {months[month - 1]}</span><strong>{Math.round(actualPct)}% contracted / {Math.round(targetPct)}% planned · {Math.max(0, 100 - totalPlanned).toFixed(0)}% unplanned remainder</strong></div><span className={`status-chip ${status === 'On Track' ? 'on-track' : status === 'Behind' ? 'behind' : 'not-started'}`}>{status}</span></div> }

function ActualVsPlan({ estimate, workspace }: { estimate: ProductionEstimate; workspace: GrainWorkspace }) { const scope = scopeOf(estimate); const production = activeProduction(estimate); const targets = scopeRows(workspace.marketing_plan_targets, scope).sort((left, right) => left.target_month.localeCompare(right.target_month)); const sold = scopeRows(workspace.grain_contracts, scope).reduce((sum, contract) => sum + contract.bushels, 0); let cumulative = 0; return <section className="grain-section actual-plan-card"><div className="section-heading"><div><span className="eyebrow">Follow-through</span><h2>Actual vs. plan</h2><p>Signed contracts are shown against your cumulative plan.</p></div></div><div className="progress-track" aria-label={`${Math.round(production ? sold / production * 100 : 0)} percent contracted`}><span style={{ width: `${Math.min(100, production ? sold / production * 100 : 0)}%` }} /></div><div className="table-scroll"><table><thead><tr><th>Month</th><th className="align-right">Plan %</th><th className="align-right">Plan bu</th><th className="align-right">Cumulative plan</th><th className="align-right">Actual sales</th></tr></thead><tbody>{targets.length ? targets.map((target) => { cumulative += target.target_pct_of_production; return <tr key={target.id}><td>{months[Number(target.target_month.slice(5, 7)) - 1]}</td><td className="align-right numeric">{target.target_pct_of_production}%</td><td className="align-right numeric">{bushels.format(production * target.target_pct_of_production / 100)}</td><td className="align-right numeric">{cumulative}%</td><td className="align-right numeric">{bushels.format(sold)} bu</td></tr> }) : <tr><td colSpan={5}>No plan yet. Choose a template or tap a month to start.</td></tr>}</tbody></table></div></section> }

function ContractEntry({ workspace, scope, services, onSaved }: { workspace: GrainWorkspace; scope: PositionScope; services: GrainServices; onSaved: () => Promise<void> }) { const buyers = [...new Set(workspace.cash_bids.filter((bid) => !isMarsBid(bid)).map((bid) => bid.elevator))]; const [buyer, setBuyer] = useState(buyers[0] ?? ''); const [type, setType] = useState<GrainContractType>('forward_cash'); const [bushelCount, setBushelCount] = useState(''); const [price, setPrice] = useState(''); const [basis, setBasis] = useState(''); const [start, setStart] = useState(`${scope.crop_year}-09-01`); const [end, setEnd] = useState(`${scope.crop_year}-11-30`); const [number, setNumber] = useState(''); const [premium, setPremium] = useState(''); const [error, setError] = useState(''); const submit = async (event: FormEvent) => { event.preventDefault(); const timestamp = new Date().toISOString(); const contract: GrainContract = { id: services.createGrainId(), ...scope, contract_type: type, buyer, bushels: Number(bushelCount), cash_price: type === 'cash_spot' || type === 'forward_cash' ? Number(price) : null, futures_price: type === 'hta' ? Number(price) : null, basis: type === 'basis' ? Number(basis) : null, delivery_start: start || null, delivery_end: end || null, contract_number: number || null, premium_cents_per_bu: premium === '' ? 0 : Number(premium), notes: null, created_at: timestamp, updated_at: timestamp }; try { await services.grainRepository.saveContract(contract); setBushelCount(''); setPrice(''); setBasis(''); setNumber(''); setPremium(''); setError(''); await onSaved() } catch (exception) { setError(exception instanceof Error ? exception.message : 'Unable to add contract.') } }; const needsPrice = type !== 'basis'; const priceLabel = type === 'hta' ? 'Futures $/bu' : 'Cash $/bu'; return <form className="contract-entry" onSubmit={(event) => void submit(event)}><label><span>Buyer</span><select value={buyer} onChange={(event) => setBuyer(event.target.value)}>{buyers.map((item) => <option key={item}>{item}</option>)}</select></label><label><span>Type</span><select value={type} onChange={(event) => setType(event.target.value as GrainContractType)}>{Object.entries(contractLabels).map(([value, label]) => <option key={value} value={value}>{label}</option>)}</select></label><label><span>Bushels</span><input required type="number" min="1" inputMode="numeric" value={bushelCount} onChange={(event) => setBushelCount(event.target.value)} /></label>{needsPrice ? <label><span>{priceLabel}</span><input required type="number" min="0" step="0.01" inputMode="decimal" value={price} onChange={(event) => setPrice(event.target.value)} /></label> : <label><span>Basis $/bu</span><input required type="number" step="0.01" inputMode="decimal" value={basis} onChange={(event) => setBasis(event.target.value)} /></label>}<details><summary>Delivery, contract #, premium</summary><div><label>Start<input type="date" value={start} onChange={(event) => setStart(event.target.value)} /></label><label>End<input type="date" value={end} onChange={(event) => setEnd(event.target.value)} /></label><label>Contract #<input value={number} onChange={(event) => setNumber(event.target.value)} /></label><label>IP premium ¢/bu<input type="number" min="0" step="0.01" inputMode="decimal" value={premium} onChange={(event) => setPremium(event.target.value)} /></label></div></details>{error && <p className="form-error grain-inline-error" role="alert">{error}</p>}<button className="primary-action" type="submit">Add contract</button></form> }

function Bins({ workspace }: { workspace: GrainWorkspace }) { return <section className="bins-card"><div className="section-heading"><div><span className="eyebrow">Storage</span><h2>Grain bins</h2></div></div><div className="bin-list">{workspace.grain_bins.map((bin) => { const inventory = workspace.bin_inventory.find((item) => item.grain_bin_id === bin.id); const commodity = inventory && workspace.fields.commodities.find((item) => item.id === inventory.commodity_id); const free = inventory ? inventory.bushels - inventory.committed_bushels : 0; return <article className="bin-row" key={bin.id}><div><strong>{bin.name}</strong><span>{bin.location_type === 'on_farm' ? 'On farm' : 'Commercial'} · {bushels.format(bin.capacity_bu)} bu cap.</span></div>{inventory ? <><span className={`commodity-badge ${commodity?.traits.identity_preserved ? 'ip' : ''}`}>{commodity?.traits.identity_preserved ? 'IP · ' : ''}{commodity?.name}</span><div className="bin-balance"><span><strong>{bushels.format(inventory.committed_bushels)}</strong> committed</span><span><strong>{bushels.format(free)}</strong> free</span></div></> : <span>Empty</span>}</article> })}</div></section> }

function Basis({ workspace, services, onSaved }: { workspace: GrainWorkspace; services: GrainServices; onSaved: () => Promise<void> }) { const [elevator, setElevator] = useState('Cargill - Olney'); const [commodity, setCommodity] = useState('corn_yellow'); const [basis, setBasis] = useState(''); const [cashPrice, setCashPrice] = useState(''); const [error, setError] = useState(''); const submit = async (event: FormEvent) => { event.preventDefault(); const parsedCashPrice = cashPrice === '' ? null : Number(cashPrice); if (parsedCashPrice !== null && (!Number.isFinite(parsedCashPrice) || parsedCashPrice < 0)) { setError('Cash price must be zero or more.'); return } const timestamp = new Date().toISOString(); try { await services.grainRepository.saveCashBid({ id: services.createGrainId(), farm_id: workspace.fields.farm.id, elevator, commodity_id: commodity, bid_date: new Date().toISOString().slice(0, 10), basis: Number(basis), cash_price: parsedCashPrice, delivery_start: null, delivery_end: null, notes: null, created_at: timestamp, updated_at: timestamp }); setBasis(''); setCashPrice(''); setError(''); await onSaved() } catch (exception) { setError(farmerError(exception, 'save this cash bid')) } }; const history = workspace.cash_bids.filter((bid) => bid.elevator === elevator && bid.commodity_id === commodity).sort((left, right) => left.bid_date.localeCompare(right.bid_date)).slice(-8); const max = Math.max(0.01, ...history.map((bid) => Math.abs(bid.basis))); const mars = history.filter(isMarsBid); const lastMars = mars.at(-1)?.bid_date; const stale = !!lastMars && Date.now() - new Date(`${lastMars}T23:59:59Z`).getTime() > 36 * 60 * 60 * 1000; return <section className="basis-card"><div className="section-heading"><div><span className="eyebrow">Cash market</span><h2>Basis history</h2><p>Recent basis by elevator and commodity. {mars.length ? `USDA MARS 2850 Iowa pilot, display-only; last dated ${lastMars}.` : ''}</p>{stale && <p role="status">Basis feed unavailable — last updated {lastMars}.</p>}</div></div><form className="basis-entry" onSubmit={(event) => void submit(event)}><select value={elevator} onChange={(event) => setElevator(event.target.value)}>{[...new Set(workspace.cash_bids.map((bid) => bid.elevator))].map((item) => <option key={item}>{item}</option>)}</select><select value={commodity} onChange={(event) => setCommodity(event.target.value)}>{workspace.fields.commodities.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select><input required type="number" step="0.01" inputMode="decimal" aria-label="Basis dollars per bushel" placeholder="Basis $/bu" value={basis} onChange={(event) => setBasis(event.target.value)} /><input type="number" min="0" step="0.01" inputMode="decimal" aria-label="Cash price dollars per bushel optional" placeholder="Cash price $/bu (optional)" value={cashPrice} onChange={(event) => setCashPrice(event.target.value)} /><button className="secondary-action" type="submit">Add basis</button></form>{error && <p className="form-error grain-inline-error" role="alert">{error}</p>}<svg className="basis-chart" viewBox="0 0 320 150" role="img" aria-label={`Basis history for ${elevator}`}><line x1="0" x2="320" y1="75" y2="75" className="basis-zero" />{history.map((bid, index) => { const height = Math.abs(bid.basis) / max * 60; const x = 16 + index * 38; const y = bid.basis >= 0 ? 75 - height : 75; return <g key={bid.id}><rect x={x} y={y} width="24" height={height} className={bid.basis >= 0 ? 'basis-positive' : 'basis-negative'} /><text x={x + 12} y="142" textAnchor="middle">{bid.bid_date.slice(5)}</text></g> })}</svg><div className="basis-list">{history.slice().reverse().map((bid) => <div key={bid.id}><span>{new Date(`${bid.bid_date}T00:00:00`).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span><strong>{bid.basis > 0 ? '+' : ''}{money.format(bid.basis)}</strong>{bid.cash_price !== null && <small>Cash {money.format(bid.cash_price)}</small>}</div>)}</div></section> }

function UsdaCalendar({ reports }: { reports: GrainWorkspace['usda_report_dates'] }) { const upcoming = reports.slice().sort((left, right) => left.report_date.localeCompare(right.report_date)); return <section className="grain-section usda-calendar"><div className="section-heading"><div><span className="eyebrow">USDA calendar</span><h2>Market-moving report dates</h2><p>2026 WASDE, Grain Stocks, Prospective Plantings, and Crop Progress dates.</p></div></div><div className="report-grid">{upcoming.map((report) => <a key={report.id} href={report.source_url ?? undefined} target="_blank" rel="noreferrer"><strong>{report.report_name}</strong><span>{new Date(`${report.report_date}T00:00:00`).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}{report.release_at ? ` · ${new Date(report.release_at).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' })}` : ''}</span></a>)}</div></section> }

function TargetEditor({ month, commodity, target, scope, services, workspace, onClose, onSave }: { month: number; commodity: string; target?: MarketingPlanTarget; scope: PositionScope; services: GrainServices; workspace: GrainWorkspace; onClose: () => void; onSave: (values: { pct: number; price: number | null; relativePct: number | null; deadline: string | null }) => void }) { const [pct, setPct] = useState(String(target?.target_pct_of_production ?? '')); const [price, setPrice] = useState(target?.target_price?.toString() ?? ''); const [relative, setRelative] = useState(target?.breakeven_relative_pct?.toString() ?? ''); const [deadline, setDeadline] = useState(target?.deadline ?? ''); const [breakeven, setBreakeven] = useState<number | null>(null); useEffect(() => { void services.profitabilityRepository.getBreakeven(scope, workspace.fields).then(setBreakeven) }, [services, scope.farm_id, scope.crop_year, scope.commodity_id, scope.operating_entity_id, scope.enterprise_label, workspace.fields]); const relativeValue = relative === '' ? null : Number(relative); const computedPrice = breakeven !== null && relativeValue !== null && Number.isFinite(relativeValue) ? breakeven * (1 + relativeValue / 100) : null; return <div className="target-modal-backdrop" role="presentation"><form className="target-modal" onSubmit={(event) => { event.preventDefault(); onSave({ pct: Number(pct), price: computedPrice ?? (price === '' ? null : Number(price)), relativePct: relativeValue, deadline: deadline || null }) }}><div className="modal-heading"><div><span className="eyebrow">{months[month - 1]} plan</span><h2>{commodity}</h2></div><button className="text-action" type="button" onClick={onClose}>Close</button></div><label>Target % of production<input required type="number" min="0.01" max="100" step="0.01" inputMode="decimal" value={pct} onChange={(event) => setPct(event.target.value)} /></label><label>Target price $/bu <small>optional</small><input type="number" min="0" step="0.01" inputMode="decimal" value={price} disabled={relative !== ''} onChange={(event) => setPrice(event.target.value)} /></label><label>ROI target: % over breakeven <small>optional; computed price is stored</small><input type="number" step="0.1" inputMode="decimal" value={relative} onChange={(event) => setRelative(event.target.value)} /></label>{relative !== '' && <p className="computed-price">Breakeven {breakeven === null ? 'not available' : money.format(breakeven)} → target {computedPrice === null ? '—' : money.format(computedPrice)}</p>}<label>Deadline <small>optional</small><input type="date" value={deadline} onChange={(event) => setDeadline(event.target.value)} /></label><button className="primary-action" type="submit">Save target</button></form></div> }
